#include "conv_pointwise_2d_custom_tiling.h"
#include "register/op_def_registry.h"

namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 2048;
static constexpr uint32_t MAX_TILE_COUT = 16;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvPointwise2dCustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);
    uint32_t N  = x_shape->GetDim(0);
    uint32_t C  = x_shape->GetDim(1);
    uint32_t H  = x_shape->GetDim(2);
    uint32_t W  = x_shape->GetDim(3);
    uint32_t Cout = w_shape->GetDim(0);
    uint32_t Cin  = w_shape->GetDim(1);

    uint32_t M = N * H * W;
    uint32_t totalLength = M * Cout;

    // Weight size
    uint32_t weightElems = Cout * Cin;
    uint32_t weightBytes = weightElems * sizeof(float);
    uint32_t remainingBytes = (UB_BUDGET_BYTES > weightBytes) ?
                              (UB_BUDGET_BYTES - weightBytes) : 0;

    // tileCout
    uint32_t tileCout = (Cout > MAX_TILE_COUT) ? MAX_TILE_COUT : Cout;
    // For simplicity, use tileHW = 1 (process one spatial position at a time)
    uint32_t tileHW = 1;

    // block dimension: assign contiguous spatial ranges
    uint32_t numTiles = CeilDiv(M, tileHW);
    uint32_t blockDim = numTiles;
    if (blockDim < 8)  blockDim = 8;
    if (blockDim > 24) blockDim = 24;

    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_M(M);
    tiling.set_Cin(Cin);
    tiling.set_Cout(Cout);
    tiling.set_tileHW(tileHW);
    tiling.set_tileCout(tileCout);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

namespace ge {
static ge::graphStatus InferShape(gert::InferShapeContext *context)
{
    // Output shape same as input shape except channel dimension replaced by Cout
    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);
    gert::Shape *y_shape = context->GetOutputShape(0);
    // output: (N, Cout, H, W)
    std::vector<int64_t> dims = {x_shape->GetDim(0),
                                 static_cast<int64_t>(w_shape->GetDim(0)),
                                 x_shape->GetDim(2),
                                 x_shape->GetDim(3)};
    *y_shape = gert::Shape(dims);
    return GRAPH_SUCCESS;
}

